let tekst;
if (!doelwit.length) tekst = "Dit raakt niemand in het bijzonder.";
else if (d.type === "uur") tekst = "Getroffen uren: " + doelwit.join(", ") + ".";
else tekst = "Getroffen spelers: " + doelwit.join(", ") + ".";
function _veilig(s){return String(s).toLowerCase().replace(/[^a-z0-9]+/g,"_");}
const _segD = ["doelwit/voor.wav"];
for (const _t of doelwit) _segD.push(d.type === "uur" ? "uren/" + _t + ".wav" : "spelers/" + _veilig(_t) + ".wav");
_segD.push("doelwit/na.wav");
