let lijnen = [];
global.set("pofDoelwitReveal", "");

// Voorlopige controle-tabel: alle spelers, status 'afwachten...'
const spelersLijst = global.get("spelersLijst") || {};
const loc = global.get("spelerLocaties") || {};
const se = global.get("spelerEffecten") || {};
const we = global.get("wereldEffecten") || [];
const bord = global.get("bordStaat") || {};
const doelSet = new Set(doelwit);
let beginRijen = [];
for (const mac in spelersLijst) {
    const naam = spelersLijst[mac];
    const paalFX = ((bord[loc[naam]] || {}).effecten || []).map(e => e.naam);
    const allFX = [...(se[naam] || []).map(e => e.naam), ...we.map(e => e.naam), ...paalFX];
    beginRijen.push({ Speler: naam, Tag: allFX.length ? allFX.join(", ") : "-", Verplaatst: 0, Status: doelSet.has(naam) ? "afwachten..." : "-" });
}
if (!beginRijen.length) beginRijen = [{ Speler:"-", Tag:"-", Verplaatst:"-", Status:"afwachten..." }];

namen.forEach((naam, i) => {
    setTimeout(() => {
        lijnen.push("\u2022 " + naam);
        const tekst = lijnen.join("\n");
        global.set("pofDoelwitReveal", tekst);
        // Buzzer-piep (actie 23) bij dit afgeroepen uur, enkel voor uur-doelwitten
        const buzz = uurType ? { payload: { paal: naam, actie: 23 } } : null;
        node.send([{ payload: tekst }, null, null, buzz]);
    }, i * STAP);
});
// Auto-modus: na de laatste naam de reactietijd starten via Voer gevolg uit.
if (!msg._manueel) {
    setTimeout(() => { node.send([null, msg, null, null]); }, namen.length * STAP + 600);
}
return [null, null, { payload: beginRijen }, null];

let P = global.get("locParams");
if (!P) { P = { vensterMs:6000, hystereseDbm:6, rssiVloer:-92, graceMs:4000, switchSamples:2, minSamples:2 }; global.set("locParams", P); }
return [ {payload:P.vensterMs}, {payload:P.hystereseDbm}, {payload:P.rssiVloer}, {payload:P.graceMs}, {payload:P.switchSamples}, {payload:P.minSamples} ];

let P = global.get("locParams") || {};
const map = { venster:"vensterMs", hysterese:"hystereseDbm", vloer:"rssiVloer", grace:"graceMs", switch:"switchSamples", minsamp:"minSamples" };
const k = map[msg.topic];
if (k) { P[k] = Number(msg.payload); global.set("locParams", P); }
msg.payload = "Actief: " + JSON.stringify(global.get("locParams"));
return msg;

// Verzamel per beacon-MAC ruwe RSSI-samples voor stabiliteitsanalyse.
const d = msg.payload;
if (!d || d.mac === undefined || d.rssi === undefined) return null; // batterij-regels overslaan
const nu = Date.now();
let buf = global.get("beaconBuf") || {};
(buf[d.mac] = buf[d.mac] || []).push({ rssi: d.rssi, ts: nu, paal: d.paal });
if (buf[d.mac].length > 400) buf[d.mac] = buf[d.mac].slice(-400);
global.set("beaconBuf", buf);
return null;

const nu = Date.now();
const VENSTER = 15000;
let buf = global.get("beaconBuf") || {};
const spelers = global.get("spelersLijst") || {};
const kal = global.get("beaconKalibratie") || {};
let rows = [], lijst = [];
for (const mac in buf) {
    let arr = buf[mac].filter(x => nu - x.ts <= VENSTER);
    buf[mac] = arr;
    if (!arr.length) { delete buf[mac]; continue; }
    const n = arr.length;
    const dur = Math.max(1, (nu - arr[0].ts) / 1000);
    const rate = n / dur;
    const mean = arr.reduce((a,b)=>a+b.rssi,0)/n;
    const sd = Math.sqrt(arr.reduce((a,b)=>a+Math.pow(b.rssi-mean,2),0)/n);
    let maxGap = 0;
    for (let i=1;i<arr.length;i++) maxGap = Math.max(maxGap, arr[i].ts-arr[i-1].ts);
    const palen = new Set(arr.map(x=>x.paal)).size;
    let score = 100 - sd*4 - Math.max(0,maxGap-1500)/40 - Math.max(0,3-rate)*15;
    score = Math.max(0, Math.min(100, Math.round(score)));
    let advies = "OK";
    if (rate < 1.2) advies = "adv-interval verlagen (300 ms)";
    else if (maxGap > 4000) advies = "mist advertenties - batterij/positie";
    else if (sd > 8) advies = "plaatsing/antenne/tx-power";
    const naam = spelers[mac] || "(onbekend)";
    rows.push({ Beacon: naam, MAC: mac, Rate: rate.toFixed(1), "RSSI sigma": sd.toFixed(1), MaxGap: Math.round(maxGap)+"ms", Palen: palen, Score: score, Offset: (kal[mac]||0)+" dB", Advies: advies });
    lijst.push({ mac, naam, offset: kal[mac]||0, score });
}
global.set("beaconBuf", buf);
rows.sort((a,b)=>a.Score-b.Score);
lijst.sort((a,b)=>a.score-b.score);
return [{ payload: rows }, { payload: lijst }];

if (!msg.payload || !msg.payload.mac) return null;
let K = global.get("beaconKalibratie") || {};
K[msg.payload.mac] = Number(msg.payload.offset) || 0;
global.set("beaconKalibratie", K);
return null;

const loc = global.get("spelerLocaties") || {};
const spel = global.get("pofHuidigSpel") || null;
return [
  { topic: "locatie/spelers", payload: loc },
  { topic: "spel/historie", payload: spel ? { actief: true, start: spel.start, events: spel.events } : { actief: false, events: [] } }
];

const hist = global.get("spelHistorie") || [];
const fmt = (iso) => { try { return new Date(iso).toLocaleString("nl-BE"); } catch(e){ return iso; } };
msg.payload = hist.map(s => ({
  id: s.id,
  start: fmt(s.start),
  aantal: s.events.length,
  events: s.events.map(e => ({ nr: e.nr, tekst: e.tekst, doelwit: e.doelwit || [], getalWaarde: e.getalWaarde }))
}));
return msg;

if (msg.delete && Array.isArray(msg.delete)) {
    const weg = new Set(msg.delete.map(Number));
    let hist = global.get("spelHistorie") || [];
    hist = hist.filter(s => !weg.has(s.id));
    global.set("spelHistorie", hist);
}
return msg;

if (global.get("rssiDiagAan") !== true) { msg.payload = []; return msg; }
const nu = Date.now();
const VENSTER = 6000;
const buf = global.get("beaconBuf") || {};
const spelers = global.get("spelersLijst") || {};
let rows = [];
for (const mac in buf) {
    const per = {};
    for (const s of buf[mac]) {
        if (nu - s.ts > VENSTER) continue;
        (per[s.paal] = per[s.paal] || []).push(s.rssi);
    }
    const naam = spelers[mac] || "(onbekend)";
    for (const paal in per) {
        const arr = per[paal];
        rows.push({ Beacon: naam, Paal: Number(paal), Laatste: arr[arr.length-1], Min: Math.min(...arr), Max: Math.max(...arr), n: arr.length });
    }
}
rows.sort((a,b) => a.Beacon.localeCompare(b.Beacon) || b.Laatste - a.Laatste);
msg.payload = rows;
return msg;

const sim24 = msg.payload && msg.payload.sim24 === true;
global.set("simVeld24", sim24);
const palen = sim24 ? Array.from({length:24},(_,i)=>i+1) : (global.get("paaltjesLijst")||[]);
global.set("palenActief", palen);
return null;

const lijst = msg.payload || [];
const spelers = global.get("spelersLijst") || {};
let loc = global.get("spelerLocaties") || {};
let bewegingen = [];
const nu = Date.now();
let seenMac = global.get("status_lastSeenMac") || {};
let seenPaal = global.get("status_lastSeenPaal") || {};
for (const d of lijst) {
    const naam = spelers[d.mac]; if (!naam) continue;
    const vorige = loc[naam];
    if (vorige !== d.paal) bewegingen.push({ payload: { speler: naam, vanPaal: (vorige !== undefined ? vorige : d.paal), naarPaal: d.paal } });
    loc[naam] = d.paal;
    seenMac[d.mac] = nu;
    seenPaal[d.paal] = nu;
}
global.set("spelerLocaties", loc);
global.set("status_lastSeenMac", seenMac);
global.set("status_lastSeenPaal", seenPaal);
global.set("status_lastDataTs", nu);
return [ null, bewegingen.length ? bewegingen : null ];

const spelers = global.get("spelersLijst")||{};
const loc = global.get("spelerLocaties")||{};
const stats = global.get("spelerStats")||{};
let rows=[];
for (const mac in spelers){
    const n = spelers[mac];
    const t = (stats[n] && stats[n].totaalUren) || 0;
    rows.push({ Speler:n, Locatie: (loc[n]!=null?"Paal "+loc[n]:"-"), RSSI:"-", Levensdagen: Math.floor(t/24), Levensuren: t%24, Achterstand: (stats[n] && stats[n].achterstand)||0 });
}
msg.payload = rows;
return msg;
